import collections
import time
import threading

class TaskScheduler:
    def __init__(self):
        self._queue = collections.deque()
        self._running = False
        self._worker_thread = None

    def add_task(self, task_function, *args, **kwargs):
        self._queue.append((task_function, args, kwargs))

    def _process_task(self):
        if not self._queue:
            return False

        task_function, args, kwargs = self._queue.popleft()
        try:
            time.sleep(0.1)  # Görev yürütme süresini simüle eder
            task_function(*args, **kwargs)
        except Exception:
            pass # Hata yönetimi burada yapılabilir
        return True

    def _run_loop(self):
        while self._running or self._queue:
            if self._queue:
                self._process_task()
            else:
                if self._running:
                    time.sleep(0.01)  # CPU kullanımını azaltmak için bekle
                else:
                    break

    def start(self):
        if self._running:
            return

        self._running = True
        self._worker_thread = threading.Thread(target=self._run_loop)
        self._worker_thread.start()

    def stop(self):
        if not self._running:
            return

        self._running = False
        if self._worker_thread and self._worker_thread.is_alive():
            self._worker_thread.join()

    def has_pending_tasks(self):
        return bool(self._queue)

    def get_queue_size(self):
        return len(self._queue)
